What is the output of the following code snippet?
#include<stdio.h>
main(){
int x=65, *p=&x;
void *q=p;
char *r=q;
printf("%c",*r);
}

What is the output of the following C-program?
#include<stdio.h>
int main()
{
const int a=10;
printf("%d", ++a);
return 0;
}

What is the output of the following C-program?
#include<stdio.h>
#define CUBE(x) (x*x*x)
int main()
{
int a, b=3;
a=CUBE(b++);
printf("%d, %d\n", a, b);
return 0;
}

What is the output of following C code?
int main()
{
int x = 2, y=1;
x*=x+y;
printf("%d", x);
}

What is the output of the following code snippet?
#include <stdio.h>
int main()
{
int x;
x=5>8?10:1!=2<5?20:30;
printf("%d",x);
return 0;
}

What will be the output of the C code?
#include <stdio.h>
int main()
{
int a=1;
if(a--)
printf("True");
if(a++)
print("False");
}

What is the output of the C-program?
#include<stdio.h>
int main()
{
int i=0;
int x=i++;
y=++i;
printf("%d %d", x, y);
}

What is the output of the C-program?
#include<stdio.h>
int main()
{
int i=0;
while(i=0)
printf("\n True");
printf("\n False");
}

What is the output of the following code snippet?
main() {
int i, k=5;
if(i=k) {
printf("YES\n");
}
else {
printf("NO\n");
}
}

What is the output of the following C-program?
#include<stdio.h>
int main()
{
int a=20;
printf ("CINEMA");
return 1;
printf ("DINOSAUR");
return 1;
}

What is the return value of f(p,p), if the value of p is initialized to 5 before the call?
int f(int &x, int c) {
c=c-1;
if (c==0) return 1;
x=x+1;
return f(x,c)*x;
}
